#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            int min = arr[i];
            int max = arr[i];
            for (int k = i; k <= j; k++) {
                if (arr[k] < min) min = arr[k];
                if (arr[k] > max) max = arr[k];
            }
            if (max - min == j - i) count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

