const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let arr;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        arr = input.split(' ').map(Number);
        let count = 0;
        for (let i = 0; i < n; i++) {
            for (let j = i; j < n; j++) {
                let min = arr[i];
                let max = arr[i];
                for (let k = i; k <= j; k++) {
                    if (arr[k] < min) min = arr[k];
                    if (arr[k] > max) max = arr[k];
                }
                if (max - min == j - i) count++;
            }
        }
        console.log(count);
        rl.close();
    }
});
